class Solution {
    public int minSwapsCouples(int[] row) {
        int n = row.length;
        int[] partner = new int[n];
        int[] pos = new int[n];
        for (int i = 0; i < n; i++) {
            partner[i] = i % 2 == 0 ? i + 1 : i - 1;
            pos[row[i]] = i;
        }
        int swaps = 0;
        for (int i = 0; i < n; i += 2) {
            if (row[i + 1] != partner[row[i]]) {
                int x = pos[partner[row[i]]];
                int temp = row[i + 1];
                row[i + 1] = row[x];
                row[x] = temp;
                pos[temp] = x;
                pos[row[i + 1]] = i + 1;
                swaps++;
            }
        }
        return swaps;
    }
}
efficiency: HIGH
time complexity: O(n)
space complexity: O(n)
